import type { SwitchCompactEmits, SwitchCompactProps, SwitchCompactSlots, SwitchUi } from '@soybeanjs/headless/switch';
import type { AcceptableBooleanValue, ClassValue } from '@soybeanjs/headless/types';
import type { SwitchShape } from '@/styles/switch';
import type { ThemeColor, ThemeSize } from '@/theme';

/**
 * Properties for the Switch component.
 */
export interface SwitchProps<T extends AcceptableBooleanValue = boolean> extends SwitchCompactProps<T> {
  /**
   * Additional class names applied to the root element.
   */
  class?: ClassValue;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<SwitchUi>;
  /**
   * Theme color of the component.
   */
  color?: ThemeColor;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Shape of the component.
   */
  shape?: SwitchShape;
}

/**
 * Events for the Switch component.
 */
export type SwitchEmits<T extends AcceptableBooleanValue = boolean> = SwitchCompactEmits<T>;

/**
 * Slots for the Switch component.
 */
export type SwitchSlots<T extends AcceptableBooleanValue = boolean> = SwitchCompactSlots<T>;

export type { SwitchShape };

// @unocss-include
import { scv } from '@soybeanjs/cva';
import type { VariantProps } from '@soybeanjs/cva';

export const switchVariants = scv({
  slots: {
    root: 'inline-flex',
    control: [
      `peer shrink-0 inline-flex items-center rounded-full border-0 shadow-sm transition-colors-200`,
      `outline-none focus-visible:ring-3  focus-visible:ring-offset-background disabled:cursor-not-allowed disabled:opacity-50 data-[state=unchecked]:bg-input`
    ],
    thumb: [
      `flex justify-center items-center rounded-full shadow-lg transition-transform-200 bg-background pointer-events-none`,
      `data-[state=unchecked]:translate-x-0.5 rtl:data-[state=unchecked]:-translate-x-0.5`
    ]
  },
  variants: {
    color: {
      primary: {
        control: `data-[state=checked]:bg-primary focus-visible:ring-primary/30`
      },
      destructive: {
        control: `data-[state=checked]:bg-destructive focus-visible:ring-destructive/30`
      },
      success: {
        control: `data-[state=checked]:bg-success focus-visible:ring-success/30`
      },
      warning: {
        control: `data-[state=checked]:bg-warning focus-visible:ring-warning/30`
      },
      info: {
        control: `data-[state=checked]:bg-info focus-visible:ring-info/30`
      },
      carbon: {
        control: `data-[state=checked]:bg-carbon focus-visible:ring-carbon/30`
      },
      secondary: {
        control: `data-[state=checked]:bg-secondary-foreground/20 focus-visible:ring-secondary-foreground/20`
      },
      accent: {
        control: `data-[state=checked]:bg-accent-foreground/20 focus-visible:ring-accent-foreground/20`
      }
    },
    size: {
      xs: {
        control: 'h-4 w-7',
        thumb: 'size-3 data-[state=checked]:translate-x-3.5 rtl:data-[state=checked]:-translate-x-3.5'
      },
      sm: {
        control: 'h-4.5 w-8',
        thumb: 'size-3.5 data-[state=checked]:translate-x-4 rtl:data-[state=checked]:-translate-x-4'
      },
      md: {
        control: 'h-5 w-9',
        thumb: 'size-4 data-[state=checked]:translate-x-4.5 rtl:data-[state=checked]:-translate-x-4.5'
      },
      lg: {
        control: 'h-5.5 w-10',
        thumb: 'size-4.5 data-[state=checked]:translate-x-5 rtl:data-[state=checked]:-translate-x-5'
      },
      xl: {
        control: 'h-6 w-11',
        thumb: 'size-5 data-[state=checked]:translate-x-5.5 rtl:data-[state=checked]:-translate-x-5.5'
      },
      '2xl': {
        control: 'h-7 w-13',
        thumb: 'size-6 data-[state=checked]:translate-x-6.5 rtl:data-[state=checked]:-translate-x-6.5'
      }
    },
    shape: {
      rounded: {
        control: 'rounded-full',
        thumb: 'rounded-full'
      },
      square: {
        control: 'rounded-md',
        thumb: 'rounded-sm'
      }
    }
  },
  defaultVariants: {
    color: 'primary',
    size: 'md',
    shape: 'rounded'
  }
});

type SwitchVariants = VariantProps<typeof switchVariants>;

export type SwitchShape = NonNullable<SwitchVariants['shape']>;

import type { ThemeSize } from './types';

export const themeSizeMap: Record<ThemeSize, number> = {
  xs: 12,
  sm: 14,
  md: 16,
  lg: 18,
  xl: 20,
  '2xl': 24
};
export const miniSizeMap: Record<ThemeSize, ThemeSize> = {
  xs: 'xs',
  sm: 'xs',
  md: 'sm',
  lg: 'md',
  xl: 'lg',
  '2xl': 'xl'
};

export const themeSizeRatio = Object.fromEntries(
  Object.entries(themeSizeMap).map(([key, value]) => [key, value / themeSizeMap.md])
) as Record<ThemeSize, number>;
